import React, { useState } from 'react';
import styled from 'styled-components';
import { supabase } from '../supabaseClient';

const Container = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  padding: 20px;
  background: #f5f5f5;
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
  gap: 20px;
  width: 100%;
  max-width: 400px;
  padding: 30px;
  background: white;
  border-radius: 10px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
`;

const Input = styled.input`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 5px;
  font-size: 16px;
`;

const Button = styled.button`
  padding: 12px;
  background: #4CAF50;
  color: white;
  border: none;
  border-radius: 5px;
  font-size: 16px;
  cursor: pointer;
  transition: background 0.3s;

  &:hover {
    background: #45a049;
  }

  &:disabled {
    background: #cccccc;
    cursor: not-allowed;
  }
`;

const ErrorMessage = styled.div`
  color: #ff0000;
  font-size: 14px;
  margin-top: 10px;
`;

const RequestAccess = ({ onAccessGranted }) => {
  const [code, setCode] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const { data, error } = await supabase
        .from('access_requests')
        .select('status')
        .eq('code', code)
        .single();

      if (error) throw error;

      if (!data) {
        setError('კოდი არ არის ნაპოვნი');
        return;
      }

      if (data.status === 'blocked') {
        setError('თქვენი წვდომა დაბლოკილია');
        return;
      }

      if (data.status !== 'approved') {
        setError('კოდი არ არის დადასტურებული');
        return;
      }

      localStorage.setItem('accessCode', code);
      onAccessGranted();
      
    } catch (error) {
      console.error('Error:', error);
      setError('დაფიქსირდა შეცდომა, სცადეთ თავიდან');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Container>
      <Form onSubmit={handleSubmit}>
        <h2>შეიყვანეთ წვდომის კოდი</h2>
        <Input
          type="text"
          value={code}
          onChange={(e) => setCode(e.target.value)}
          placeholder="კოდი"
          required
        />
        <Button type="submit" disabled={isLoading}>
          {isLoading ? 'იტვირთება...' : 'შესვლა'}
        </Button>
        {error && <ErrorMessage>{error}</ErrorMessage>}
      </Form>
    </Container>
  );
};

export default RequestAccess;
